//! Integration tests for the CDQN Runtime and Chronosa Agent execution.
//!
//! These tests verify the full Cognitive Cycle (Dispatcher -> Agent -> Logic).

use crate::CdqnRuntime;
use cdqn_cdu::{Cdu, AxiomPayload, World};
use cdqn_hlc::HybridLogicalClock;
use cdqn_cryptocore::hash_sha3_256;
use std::path::PathBuf;
use std::fs;
use std::env;
use std::sync::{mpsc, Arc, Mutex, Condvar};
use std::collections::HashMap;
use std::thread;

// Helper function to create a sovereign temporary directory
fn create_sovereign_temp_dir() -> PathBuf {
    let temp_dir = env::temp_dir().join(format!("cdqn_test_manifold_{}", std::process::id()));
    fs::create_dir_all(&temp_dir).expect("Failed to create sovereign temp directory");
    temp_dir
}

// Helper function to clean up the sovereign temporary directory
fn cleanup_sovereign_temp_dir(path: &PathBuf) {
    if path.exists() {
        fs::remove_dir_all(path).expect("Failed to clean up sovereign temp directory");
    }
}

// Helper function to create a test CDU for the simulation
fn create_test_cdu(statement: &str, r_coordinate: f64, genesis_id: &[u8], node_signer: &cdqn_cryptocore::SignerEntity) -> Cdu {
    let hlc = HybridLogicalClock::new();
    
    let node_id = hash_sha3_256(node_signer.verification_key().as_bytes()).to_vec();
    
    let axiom_payload = AxiomPayload {
        statement: statement.to_string(),
    };
    let payload = axiom_payload.into_payload();

    let metadata = cdqn_cdu::Metadata {
        author_node: node_id.clone(),
        context_refs: vec![genesis_id.to_vec()], 
        state: "draft".to_string(),
        weight: 1.0,
        r_coordinate,
        world_context: World::UserWorld,
        hlc_timestamp: hlc.new_timestamp(),
        symmetric_counterpart: None,
        validated_worlds: std::collections::HashSet::new(),
        task_footprints: HashMap::new(),
    };

    let mut cdu = Cdu::new(payload, metadata, &hlc, &node_id);
    cdu.sign(node_signer, &hlc).expect("CDU signing failed in test helper");
    
    cdu
}

/// Async completion tracker using Condvar for zero-CPU-cost waiting
struct CompletionTracker {
    state: Mutex<(usize, usize)>, // (verifier_count, evolution_count)
    condvar: Condvar,
}

impl CompletionTracker {
    fn new() -> Arc<Self> {
        Arc::new(CompletionTracker {
            state: Mutex::new((0, 0)),
            condvar: Condvar::new(),
        })
    }

    fn notify_verifier_complete(&self) {
        let mut state = self.state.lock().unwrap();
        state.0 += 1;
        self.condvar.notify_all();
    }

    fn notify_evolution_complete(&self) {
        let mut state = self.state.lock().unwrap();
        state.1 += 1;
        self.condvar.notify_all();
    }

    fn wait_for_completion(&self, expected_verifier: usize, expected_evolution: usize) {
        let mut state = self.state.lock().unwrap();
        while state.0 < expected_verifier || state.1 < expected_evolution {
            state = self.condvar.wait(state).unwrap();
        }
    }
}

/// This test verifies the full Cognitive Cycle using async dispatcher with zero-CPU-cost waiting.
#[test]
fn test_full_cognitive_cycle_verifier() {
    let storage_path = create_sovereign_temp_dir();
    
    // Setup channels for agent results
    let (tx_verifier, rx_verifier) = mpsc::channel();
    let (tx_evolution, rx_evolution) = mpsc::channel();
    
    // Setup async completion tracker (replaces blocking timeouts)
    let tracker = CompletionTracker::new();
    let tracker_clone = tracker.clone();
    
    println!("TEST: Initializing CDQN Runtime...");
    let runtime = CdqnRuntime::new_with_test_channels(
        storage_path.clone(),
        Some(tx_verifier),
        Some(tx_evolution),
    );
    
    let genesis_id = runtime.manifold.genesis_id.clone();
    let test_signer = cdqn_cryptocore::SignerEntity::new_random("TestNodeSigner");

    // Spawn async result collector thread using zero-CPU-cost waiting
    let collector_handle = thread::spawn(move || {
        let mut verifier_outcomes = Vec::new();
        
        // Collect first verifier result (async, non-blocking wait)
        if let Ok(result) = rx_verifier.recv() {
            println!("TEST: Received Verifier result 1: {}", result);
            verifier_outcomes.push(result);
            tracker_clone.notify_verifier_complete();
        }
        
        // Collect second verifier result (async, non-blocking wait)
        if let Ok(result) = rx_verifier.recv() {
            println!("TEST: Received Verifier result 2: {}", result);
            verifier_outcomes.push(result);
            tracker_clone.notify_verifier_complete();
        }
        
        // Collect evolution result (async, non-blocking wait)
        let evolution_result = rx_evolution.recv().ok();
        if evolution_result.is_some() {
            tracker_clone.notify_evolution_complete();
        }
        
        (verifier_outcomes, evolution_result)
    });

    // Inject test CDUs into the async dispatcher
    println!("\nTEST: Publishing CDUs to async dispatcher...");
    let valid_cdu = create_test_cdu("Valid Axiom", 2.5, &genesis_id, &test_signer);
    runtime.dispatcher.publish(valid_cdu).expect("Failed to publish Valid CDU");

    let contradictory_cdu = create_test_cdu("Contradictory Fact", 0.5, &genesis_id, &test_signer);
    runtime.dispatcher.publish(contradictory_cdu).expect("Failed to publish Contradictory CDU");

    // Wait for async completion using Condvar (zero-CPU-cost)
    println!("\nTEST: Waiting for async agent processing (zero-CPU-cost)...");
    tracker.wait_for_completion(2, 1);

    // Collect results from async collector
    let (verifier_outcomes, evolution_result) = collector_handle.join()
        .expect("Collector thread panicked");

    // Assertions
    println!("\n=== VERIFICATION RESULTS SUMMARY ===");
    println!("Verifier Result 1: {}", verifier_outcomes.get(0).unwrap_or(&"MISSING".to_string()));
    println!("Verifier Result 2: {}", verifier_outcomes.get(1).unwrap_or(&"MISSING".to_string()));
    println!("Evolution Result: {}", evolution_result.as_ref().unwrap_or(&"MISSING".to_string()));
    println!("=====================================\n");

    assert_eq!(verifier_outcomes.len(), 2, "Expected 2 verifier results");
    
    assert!(
        verifier_outcomes.iter().any(|s| s.contains("VERIFIED (RWorld: 2.5)")),
        "Verifier failed to confirm the Valid CDU. Outcomes: {:?}", verifier_outcomes
    );

    assert!(
        verifier_outcomes.iter().any(|s| s.contains("CONTRADICTION (RWorld: 0.5)")),
        "Verifier failed to detect the Contradictory CDU. Outcomes: {:?}", verifier_outcomes
    );
    
    let evo = evolution_result.expect("Evolution agent failed to send result");
    assert!(
        evo.contains("RESOLVED: Resolved with Hash:"),
        "Evolution Agent failed to resolve the contradiction. Outcome: {}", evo
    );

    cleanup_sovereign_temp_dir(&storage_path);
    println!("TEST: Full Cognitive Cycle test completed successfully using async dispatcher!");
}
